arguments.argument:
if global.gamePaused=false
{
  if bActive=true
  {
    speed=3
  }
  else
  {
    initTime+=1
    if initTime>=1 and initTime<=9 {image_xscale+=0.1; image_yscale+=0.1}
    if initTime>=20
    {
      direction=point_direction(x,y,oPlayer1.x,returnPlayerYCenter())
      bCanDealDamage=1; bCanTakeDamage=1
      bActive=true
    }
  }
  enemyStepEvent()
}
else {speed=0}
